    function formatNumber(value) {
        if (value >= 1e9) {
            return (value / 1e9).toFixed(2) + 'B'; // หน่วยพันล้าน
        } else if (value >= 1e6) {
            return (value / 1e6).toFixed(2) + 'M'; // หน่วยล้าน
        } else if (value >= 1e3) {
            return (value / 1e3).toFixed(2) + 'K'; // หน่วยพัน
        } else {
            return value.toFixed(2); // หน่วยปกติ
        }
    }

